from __future__ import annotations

from pathlib import Path
import base64

DISPLAY = Path("src/hadocs/utils/display.py")
TEST = Path("tests/test_display_utils.py")
DOC = Path("docs/ISSUE_4_STEP1_DISPLAY_UTILS.md")

DISPLAY_TEXT = base64.b64decode("").decode("utf-8")
TEST_TEXT = base64.b64decode("").decode("utf-8")
DOC_TEXT = base64.b64decode("").decode("utf-8")


def main() -> None:
    if not Path("src/hadocs").exists():
        raise SystemExit("Run from repository root: C:\\HomeAssistantDocs")

    DISPLAY.parent.mkdir(parents=True, exist_ok=True)
    DISPLAY.write_text(DISPLAY_TEXT, encoding="utf-8")
    TEST.write_text(TEST_TEXT, encoding="utf-8")
    DOC.write_text(DOC_TEXT, encoding="utf-8")

    print("Issue #4 step 1 applied: display utilities only.")
    print("Run: py -3.14 -m pytest")
    print("Commit if green:")
    print("  git add src/hadocs/utils/display.py tests/test_display_utils.py docs/ISSUE_4_STEP1_DISPLAY_UTILS.md tools/apply_issue4_step1_display_utils.py")
    print('  git commit -m "Add display utilities for area labels"')


if __name__ == "__main__":
    main()
